<script setup>
import { provide, ref } from 'vue';
import AddModal from '../AddModal.vue';
import DashboardMenuLink from './DashboardMenuLink.vue';

let isModal = ref(false)

const openModal = () => {
  isModal.value = true;
  document.body.classList.toggle('modalOpened');
  document.querySelectorAll('.blured').forEach((elem) => {
    elem.classList.toggle('modalOpened')
  })
}

const closeModal = () => {
  isModal.value = false;
  document.body.classList.toggle('modalOpened');
  document.querySelectorAll('.blured').forEach((elem) => {
    elem.classList.toggle('modalOpened')
  })
}

provide('modalActions', {openModal, closeModal})

</script>

